2. **Create the Program**:

```csharp
using System;
using System.Net.Http;
using System.Text;
using System.Threading.Tasks;
using Newtonsoft.Json;

namespace CoinbaseTradeBot
{
    class Program
    {
        private static readonly string ApiKey = "YOUR_API_KEY";
        private static readonly string ApiSecret = "YOUR_API_SECRET";
        private static readonly string ApiPassphrase = "YOUR_API_PASSPHRASE";
        private static readonly string ApiUrl = "https://api.pro.coinbase.com";

        static async Task Main(string[] args)
        {
            // Example: Place a buy order for 0.01 BTC at the current market price
            var symbol = "BTC-USD";
            var side = "buy";
            var size = 0.01M; // 0.01 BTC

            var order = await PlaceOrder(symbol, side, size);
            Console.WriteLine($"Order placed successfully: {order}");
        }

        static async Task<dynamic> PlaceOrder(string product_id, string side, decimal size)
        {
            using (var client = new HttpClient())
            {
                // Create the request body
                var requestBody = new
                {
                    product_id = product_id,
                    side = side,
                    type = "market",
                    size = size.ToString()
                };

                // Set headers
                client.DefaultRequestHeaders.Add("CB-ACCESS-KEY", ApiKey);
                client.DefaultRequestHeaders.Add("CB-ACCESS-SIGN", await GenerateSignature(requestBody));
                client.DefaultRequestHeaders.Add("CB-ACCESS-TIMESTAMP", DateTimeOffset.UtcNow.ToUnixTimeMilliseconds().ToString());
                client.DefaultRequestHeaders.Add("CB-ACCESS-PASSPHRASE", ApiPassphrase);

                // Convert the request body to JSON
                var jsonContent = JsonConvert.SerializeObject(requestBody);
                var content = new StringContent(jsonContent, Encoding.UTF8, "application/json");

                // Make the POST request
                var response = await client.PostAsync($"{ApiUrl}/orders", content);

                // Read the response
                if (response.IsSuccessStatusCode)
                {
                    var responseString = await response.Content.ReadAsStringAsync();
                    return JsonConvert.DeserializeObject<dynamic>(responseString);
                }
                else
                {
                    throw new Exception($"Error placing order: {await response.Content.ReadAsStringAsync()}");
                }
            }
        }

        static async Task<string> GenerateSignature(dynamic requestBody)
        {
            // Serialize the request body
            var jsonRequestBody = JsonConvert.SerializeObject(requestBody, Formatting.None, new JsonSerializerSettings
            {
                ReferenceLoopHandling = ReferenceLoopHandling.Ignore
            });

            // Create the signing string
            var signingString = $"POST\n/order-books\n{jsonRequestBody}";

            // Create a HMACSHA256 object
            using (var hmac = new System.Security.Cryptography.HMACSHA256(Encoding.UTF8.GetBytes(ApiSecret)))
            {
                // Compute the signature
                var signature = hmac.ComputeHash(Encoding.UTF8.GetBytes(signingString));
                return Convert.ToBase64String(signature);
            }
        }
    }
}
```

### Explanation:
1. **Setup**: Define your API credentials and the API URL.
2. **PlaceOrder Method**: This method constructs the request body, sets the necessary headers, and sends the POST request to place an order.
3. **GenerateSignature Method**: This method generates the signature required by the Coinbase Pro API.
4. **Main Method**: Demonstrates how to place a buy order for 0.01 BTC at the current market price.

### Important Notes:
- **Security**: Never hard-code your API keys in your source code. Use environment variables or secure vaults to manage sensitive information.
