static int rsi_send_beacon(struct rsi_common *common)
{
    struct sk_buff *skb = NULL;
    u8 dword_align_bytes = 0;

    skb = dev_alloc_skb(MAX_MGMT_PKT_SIZE);
    if (!skb) {
